const WebSocket = require('ws');
const fs = require('fs');
const path = require('path');

/**
 * Script ini adalah mock server untuk mengetes koneksi Amaya (Android) ke ekstensi VS Code.
 * Berjalan di port 8765 dan mengirimkan output dalam format JSON.
 */

const PORT = 8765;
const wss = new WebSocket.Server({ port: PORT, host: '0.0.0.0' });

console.log(`[Test Server] Memulai server di port ${PORT}...`);

wss.on('connection', (ws) => {
    console.log('[Test Server] Client terhubung');

    // Cek workspace (list file di root project amaya)
    const workspaceRoot = path.resolve(__dirname, '..', '..');
    console.log(`[Test Server] Mengecek workspace di: ${workspaceRoot}`);

    let files = [];
    try {
        files = fs.readdirSync(workspaceRoot);
    } catch (err) {
        console.error(`[Test Server] Gagal membaca workspace: ${err.message}`);
    }

    // Output JSON
    const testData = {
        event: 'workspace_info',
        data: {
            workspacePath: workspaceRoot,
            fileCount: files.length,
            files: files.slice(0, 20), // Tampilkan 20 file pertama untuk contoh
            status: "OK",
            timestamp: new Date().toISOString()
        }
    };

    ws.send(JSON.stringify(testData));
    console.log('[Test Server] Data JSON workspace telah dikirim');

    ws.on('message', (message) => {
        console.log(`[Test Server] Pesan masuk: ${message}`);
        try {
            const parsed = JSON.parse(message);
            // Kirim respons balik
            const response = {
                event: 'response',
                data: {
                    receivedAction: parsed.action || 'none',
                    serverTime: new Date().toLocaleTimeString()
                }
            };
            ws.send(JSON.stringify(response));
        } catch (e) {
            console.warn('[Test Server] Gagal mem-parse JSON input');
        }
    });

    ws.on('close', () => {
        console.log('[Test Server] Client terputus');
    });
});

console.log(`[Test Server] ✅ Server siap! Hubungkan client ke ws://<IP_ANDA>:${PORT}`);

