wss.on('connection', (ws) => {
    console.log('[Test Server] Client connected. Sending RAW recursive workspace info...');

    const workspaceRoot = path.resolve(__dirname, '..', '..');

    // Ambil SEMUA file secara rekursif (bisa ribuan file)
    let allFiles = [];
    try {
        allFiles = fs.readdirSync(workspaceRoot, { recursive: true });
    } catch (err) {
        console.error(`[Test Server] Gagal: ${err.message}`);
        allFiles = [err.message];
    }

    // KIRIM RAW JSON ARRAY (Tanpa parsing/wrapping tambahan)
    const rawPayload = JSON.stringify(allFiles);
    ws.send(rawPayload);

    console.log(`[Test Server] Payload RAW terkirim (${allFiles.length} item, ${rawPayload.length} bytes)`);

    ws.on('message', (msg) => {
        console.log(`[Test Server] Input: ${msg}`);
        ws.send(JSON.stringify({ status: "received", size: msg.length }));
    });
});

