import * as vscode from 'vscode';
import * as WebSocket from 'ws';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import { IIDEClient, IDEConversationMode, IDEMessageAttachment } from '../interfaces/IIDEClient';
import { AntigravityClient } from '../ide/antigravity/AntigravityClient';
import { AntigravityMappers } from '../ide/antigravity/mappers/AntigravityMappers';
import { AppState } from '../types/index';

/**
 * MessageHandler.ts
 * 
 * Extracts the monolithic WebSocket command processor from `extension.ts`.
 * It routes Android APK JSON payloads directly into generic IIDEClient standard methods,
 * making the extension completely agnostic to whether "Antigravity" or "Copilot" is powering it.
 */
export class MessageHandler {
    private api: IIDEClient;
    private state: AppState;
    private wss: WebSocket.Server | null;
    private sequenceId: number = 0;
    private readonly serverSessionId: string = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
    private readonly attachedStreamIds: Set<string> = new Set();
    private readonly BUFFER_SIZE = 100;
    // Map<cascadeId, Event[]>
    private eventBuffer: Map<string, any[]> = new Map();
    private terminalBuffers: Map<string, string> = new Map();
    private hijackedResults: Map<string, string> = new Map();
    private static readonly ANSI_CLEAN_REGEX = /[\u001b\u009b][[()#;?]*(?:[0-9]{1,4}(?:;[0-9]{0,4})*)?[0-9A-ORZcf-nqry=><]|(?:\u001b\]633;.*?\u0007)/g;
    private pingInterval: NodeJS.Timeout | null = null;

    private loadingMap: Map<string, boolean> = new Map();
    private streamingMap: Map<string, boolean> = new Map();
    private streamSessionToken: Map<string, number> = new Map();
    private autoAttachInterval: NodeJS.Timeout | null = null;
    private lastAutoAttachCascadeId: string | null = null;
    private lastAutoAttachAt: number = 0;
    private lastMetadataCheckAt: number = 0;
    private lastAutoSyncAt: number = 0;
    private lastUserSendAt: number = 0;

    // Throttle for ai_thinking events (emit max once per 500ms per cascade)
    private lastAiThinkingAt: Map<string, number> = new Map();
    private readonly AI_THINKING_THROTTLE_MS = 500;
    private conversationModeMap: Map<string, IDEConversationMode> = new Map();

    // Single source of truth for streaming state
    // Only emits state_update - status_change is emitted separately when needed
    private setStreamingState(cascadeId: string, isLoading: boolean, isStreaming: boolean, emitStatusChange: boolean = false) {
        this.loadingMap.set(cascadeId, isLoading);
        this.streamingMap.set(cascadeId, isStreaming);
        if (this.state.activeCascadeId === cascadeId) {
            this.state.isLoading = isLoading;
            this.state.isStreaming = isStreaming;
        }
        this.broadcastEvent('state_update', { isLoading, isStreaming, conversationId: cascadeId }, cascadeId);
        // Only emit status_change when explicitly requested (not on every streaming state change)
        if (emitStatusChange) {
            const status = isStreaming
                ? 'CASCADE_RUN_STATUS_RUNNING'
                : (isLoading ? 'CASCADE_RUN_STATUS_UNSPECIFIED' : 'CASCADE_RUN_STATUS_IDLE');
            this.broadcastEvent('status_change', { status, conversationId: cascadeId }, cascadeId);
        }
    }

    // Debounce helper for noisy commands
    private lastCommandAt: Map<string, number> = new Map();
    private shouldRunCommand(command: string, debounceMs: number): boolean {
        const now = Date.now();
        const last = this.lastCommandAt.get(command) || 0;
        if (now - last < debounceMs) return false;
        this.lastCommandAt.set(command, now);
        return true;
    }

    private shouldLogCommand(action: string): boolean {
        return !['pong', 'get_state', 'get_conversations', 'get_models', 'get_events_since'].includes(action);
    }

    private getConversationMode(cascadeId?: string | null): IDEConversationMode {
        if (!cascadeId) return 'planning';
        return this.conversationModeMap.get(cascadeId) || 'planning';
    }

    private invalidateStream(cascadeId: string) {
        this.attachedStreamIds.delete(cascadeId);
        this.streamSessionToken.set(cascadeId, (this.streamSessionToken.get(cascadeId) || 0) + 1);
    }

    // Create streaming callbacks - single implementation used by both attach and send
    private createStreamCallbacks(cascadeId: string, token: number) {
        const checkToken = () => (this.streamSessionToken.get(cascadeId) || 0) === token;
        return {
            onToolCall: (tc: any) => {
                if (!checkToken()) return;
                this.setStreamingState(cascadeId, false, true);
                this.broadcastEvent('tool_call_start', {
                    toolCallId: tc.id,
                    name: tc.name,
                    arguments: this.safeParseJson(tc.args),
                    status: tc.status || 'RUNNING',
                    metadata: tc.metadata || {},
                    conversationId: cascadeId
                }, cascadeId);
            },
            onToolResult: (name: string, result: string, id: string, isError: boolean) => {
                if (!checkToken()) return;
                this.setStreamingState(cascadeId, false, true);
                
                let finalResult = result;
                const hijackedTools = ['run_shell', 'RUN_COMMAND', 'command_status', 'COMMAND_STATUS'];
                if (hijackedTools.includes(name) && !isError) {
                    const buffer = this.terminalBuffers.get(cascadeId);
                    console.log(`[Amaya MessageHandler] Tool ${name} done. Buffer length: ${buffer?.length || 0}`);
                    if (buffer) {
                        const cleaned = this.cleanTerminalOutput(buffer);
                        if (cleaned) {
                            console.log(`[Amaya MessageHandler] Hijacking result for ${name}. Cleaned length: ${cleaned.length}`);
                            finalResult = cleaned;
                            this.hijackedResults.set(id, cleaned);
                        } else {
                            console.log(`[Amaya MessageHandler] Cleaned buffer is empty for ${name}`);
                        }
                        // Optional: Clear buffer for next command
                        this.terminalBuffers.delete(cascadeId);
                    } else {
                        console.log(`[Amaya MessageHandler] No buffer found for cascade ${cascadeId} during ${name}`);
                    }
                }
                
                this.broadcastEvent('tool_call_result', { toolCallId: id, name, result: finalResult, isError, conversationId: cascadeId }, cascadeId);
            },
            onUserMessage: (text: string) => {
                if (!checkToken()) return;
                this.broadcastEvent('user_message', { content: text, conversationId: cascadeId }, cascadeId);
            },
            onThinking: (text: string) => {
                if (!checkToken()) return;
                this.setStreamingState(cascadeId, false, true);
                // Throttle ai_thinking events to reduce spam (max once per 500ms)
                const now = Date.now();
                const lastEmit = this.lastAiThinkingAt.get(cascadeId) || 0;
                if (now - lastEmit >= this.AI_THINKING_THROTTLE_MS) {
                    this.lastAiThinkingAt.set(cascadeId, now);
                    this.broadcastEvent('ai_thinking', { text, conversationId: cascadeId }, cascadeId);
                }
            },
            onTextDelta: (text: string) => {
                if (!checkToken()) return;
                this.setStreamingState(cascadeId, false, true);
                // Removed debug_log - not needed for Android, reduces event spam
                this.broadcastEvent('text_delta', { text, conversationId: cascadeId }, cascadeId);
            },
            onStateSync: (messages: any[]) => {
                if (!checkToken()) return;
                const mappedMessages = this.mapMessagesForUi(messages);
                const selectedModel = this.state.models.find(m => m.id === this.state.selectedModelId);
                this.broadcastEvent('state_sync', {
                    messages: mappedMessages,
                    isLoading: this.loadingMap.get(cascadeId) || false,
                    isStreaming: this.streamingMap.get(cascadeId) || false,
                    currentModel: selectedModel?.label || '',
                    conversationMode: this.getConversationMode(cascadeId),
                    conversationId: cascadeId
                }, cascadeId);
            },
            onDone: (finalText: string, stopReason?: string) => {
                if (!checkToken()) return;
                this.setStreamingState(cascadeId, false, false);
                this.broadcastEvent('stream_done', { finalText, stopReason: stopReason || 'DONE', conversationId: cascadeId }, cascadeId);
            },
            onError: (err: string) => {
                if (!checkToken()) return;
                if (/aborted/i.test(err || '')) {
                    this.setStreamingState(cascadeId, false, false);
                    this.attachedStreamIds.delete(cascadeId);
                    return;
                }
                console.error('[Amaya MessageHandler] Stream error:', err);
                this.setStreamingState(cascadeId, false, false);
                this.attachedStreamIds.delete(cascadeId);
                const formatted = this.formatErrorMessage(err);
                this.broadcastEvent('error', { message: formatted.message, raw: formatted.raw, conversationId: cascadeId }, cascadeId);
            },
            onTitleGenerated: (title: string) => {
                if (!checkToken()) return;
                this.broadcastEvent('title_generated', { title, conversationId: cascadeId }, cascadeId);
            },
            onStatusChange: (status: string) => {
                if (!checkToken()) return;
                const isLoading = status === 'CASCADE_RUN_STATUS_UNSPECIFIED' || status === 'CASCADE_RUN_STATUS_RUNNING';
                const isStreaming = status === 'CASCADE_RUN_STATUS_RUNNING';

                // Pass emitStatusChange=true to emit status_change from setStreamingState
                // This avoids double emission (we used to call broadcastEvent again here)
                this.setStreamingState(cascadeId, isLoading, isStreaming, true);
            }
        };
    }

    private formatErrorMessage(input: any): { message: string; raw: string } {
        const raw = typeof input === 'string' ? input : (() => {
            try { return JSON.stringify(input); } catch { return String(input); }
        })();

        let msg = typeof input === 'string' ? input : raw;
        msg = (msg || '').toString();

        // If the error is a JSON-ish blob, try extracting the most human-friendly message.
        // We keep it regex-based to handle partially-truncated strings.
        const pickFromRaw = (text: string): string | null => {
            if (!text) return null;
            const candidates = [
                /"userErrorMessage"\s*:\s*"([^"]+)"/i,
                /"shortError"\s*:\s*"([^"]+)"/i,
                /"modelErrorMessage"\s*:\s*"([^"]+)"/i,
                /"fullError"\s*:\s*"([^"]+)"/i,
            ];
            for (const re of candidates) {
                const m = text.match(re);
                if (m && m[1]) {
                    return m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').trim();
                }
            }
            return null;
        };

        const extracted = pickFromRaw(msg) || pickFromRaw(raw);
        if (extracted) {
            msg = extracted;
        }

        // Convert "reset after 28h25m46s" (or any compact dhms) to an absolute timestamp.
        // Example: "... will reset after 28h25m46s" -> "... will reset at 15/03/2026 00:52"
        const afterRe = /(reset\s+after\s+)([0-9dhms]+)\b/i;
        const m = msg.match(afterRe);
        if (m) {
            const dur = m[2];
            let totalMs = 0;
            const parts = Array.from(dur.matchAll(/(\d+)([dhms])/gi));
            for (const p of parts) {
                const v = parseInt(p[1], 10);
                const u = (p[2] || '').toLowerCase();
                if (isNaN(v)) continue;
                if (u === 'd') totalMs += v * 24 * 60 * 60 * 1000;
                if (u === 'h') totalMs += v * 60 * 60 * 1000;
                if (u === 'm') totalMs += v * 60 * 1000;
                if (u === 's') totalMs += v * 1000;
            }
            if (totalMs > 0) {
                const dt = new Date(Date.now() + totalMs);
                const pad = (n: number) => (n < 10 ? `0${n}` : `${n}`);
                const formatted = `${pad(dt.getDate())}/${pad(dt.getMonth() + 1)}/${dt.getFullYear()} ${pad(dt.getHours())}:${pad(dt.getMinutes())}`;
                msg = msg.replace(afterRe, `$1${formatted}`.replace(/reset after /i, 'reset at '));
            }
        }

        // Avoid sending massive JSON-ish strings to UI.
        if (msg.length > 600) msg = `${msg.substring(0, 600)}...`;
        if (!msg.trim()) msg = 'Unknown error';
        return { message: msg.trim(), raw };
    }

    constructor(api: IIDEClient, state: AppState, wss: WebSocket.Server | null) {
        this.api = api;
        this.state = state;
        this.wss = wss;
        this.startHeartbeat();
    }

    private startAutoAttach() {
        if (this.autoAttachInterval) return;
        this.autoAttachInterval = setInterval(async () => {
            if (!this.wss || this.wss.clients.size === 0) return;

            const now = Date.now();
            if (now - this.lastAutoSyncAt < 10000) return;
            if (now - this.lastUserSendAt < 3000) return;

            let activeId = (this.api as any)?.lastActiveCascadeId || this.state.activeCascadeId;
            if (!activeId && now - this.lastMetadataCheckAt > 10000) {
                this.lastMetadataCheckAt = now;
                try {
                    const metas = await this.api.getConversationsMetadata();
                    if (metas && metas.length > 0) {
                        const latest = metas.reduce((a, b) => (a.lastModified >= b.lastModified ? a : b));
                        activeId = latest?.id || null;
                    }
                } catch { /* ignore */ }
            }

            if (!activeId) return;
            if (this.attachedStreamIds.has(activeId)) return;

            if (activeId === this.lastAutoAttachCascadeId && now - this.lastAutoAttachAt < 15000) return;
            this.lastAutoAttachCascadeId = activeId;
            this.lastAutoAttachAt = now;
            this.lastAutoSyncAt = now;

            console.log(`[Amaya MessageHandler] Auto-attach stream for ${activeId}`);
            for (const ws of this.wss.clients) {
                if (ws.readyState === WebSocket.OPEN) {
                    this.handleGetState(ws as WebSocket.WebSocket).catch((e: any) => {
                        console.error('[Amaya MessageHandler] Auto get_state failed:', e?.message || e);
                    });
                }
            }
        }, 2000);
    }

    private stopAutoAttach() {
        if (this.autoAttachInterval) {
            clearInterval(this.autoAttachInterval);
            this.autoAttachInterval = null;
        }
    }

    private ensureStreamAttached(cascadeId: string) {
        if (!cascadeId) return;
        if (this.attachedStreamIds.has(cascadeId)) return;

        this.attachedStreamIds.add(cascadeId);
        const token = (this.streamSessionToken.get(cascadeId) || 0) + 1;
        this.streamSessionToken.set(cascadeId, token);
        console.log(`[Amaya MessageHandler] Stream attach for ${cascadeId}`);
        this.setStreamingState(cascadeId, true, false);

        (async () => {
            // Send initial state before streaming
            this.setStreamingState(cascadeId, false, false);
            const initialMessages = this.mapMessagesForUi(this.api.getCurrentMessages(cascadeId) || []);
            const selectedModel = this.state.models.find(m => m.id === this.state.selectedModelId);
            this.broadcastEvent('state_sync', { messages: initialMessages, isLoading: false, isStreaming: false, currentModel: selectedModel?.label || '', conversationId: cascadeId }, cascadeId);

            try {
                const callbacks = this.createStreamCallbacks(cascadeId, token);
                await this.api.streamForResponse(cascadeId, callbacks, 0, []);
                // Cleanup if stream ended without callback
                if (this.attachedStreamIds.has(cascadeId) && (this.streamSessionToken.get(cascadeId) || 0) === token) {
                    this.setStreamingState(cascadeId, false, false);
                    this.attachedStreamIds.delete(cascadeId);
                }
            } catch (e: any) {
                console.error('[Amaya MessageHandler] Stream attach error:', e.message);
                this.setStreamingState(cascadeId, false, false);
                this.attachedStreamIds.delete(cascadeId);
                this.broadcastEvent('error', { message: e.message, conversationId: cascadeId }, cascadeId);
            }
        })();
    }

    public updateServer(wss: WebSocket.Server | null) {
        this.wss = wss;
        if (this.wss) {
            this.startHeartbeat();
        } else {
            this.stopHeartbeat();
        }
    }

    public async handleCommand(msg: any, ws: WebSocket.WebSocket) {
        const { action, data = {} } = msg;
        if (this.shouldLogCommand(action)) {
            console.log(`[Amaya MessageHandler] Command: ${action}`);
        }

        switch (action) {
            case 'send_message':
                await this.handleSendMessage(
                    data.content || '',
                    ws,
                    data.id || data.conversationId,
                    data.mode === 'fast' ? 'fast' : 'planning',
                    this.parseMessageAttachments(data.attachments)
                );
                break;
            case 'new_chat':
                await this.handleNewChat(ws);
                break;
            case 'pong':
                // Heartbeat response, no action needed but keeps socket active
                break;
            case 'stop_generation':
                const stopId = data.id || data.conversationId || this.state.activeCascadeId;
                if (stopId) {
                    this.invalidateStream(stopId);
                    this.api.stopStreaming(stopId);
                    this.setStreamingState(stopId, false, false);
                    this.broadcastEvent('stream_done', { stopReason: 'USER_ABORTED', conversationId: stopId }, stopId);
                } else {
                    this.api.stopStreaming();
                    this.state.isLoading = false;
                    this.state.isStreaming = false;
                    this.broadcastEvent('stream_done', { stopReason: 'USER_ABORTED' });
                }
                break;
            case 'tool_interaction':
                if ((data.id || data.conversationId || this.state.activeCascadeId) && data.toolCallId) {
                    const interactionId = data.id || data.conversationId || this.state.activeCascadeId;
                    const accepted = !!data.accepted;
                    const ok = await this.api.respondToToolInteraction(
                        interactionId,
                        data.toolCallId,
                        accepted,
                        data.arguments || {},
                        data.metadata || {}
                    );
                    if (!ok) {
                        this.broadcastEvent('error', { message: 'Failed to respond to terminal action', conversationId: interactionId }, interactionId);
                        break;
                    }
                    if (accepted) {
                        this.broadcastEvent('tool_call_start', {
                            toolCallId: data.toolCallId,
                            name: data.name || 'run_shell',
                            arguments: data.arguments || {},
                            status: 'RUNNING',
                            metadata: { ...(data.metadata || {}), approvalState: 'resolved' },
                            conversationId: interactionId,
                        }, interactionId);
                    } else {
                        this.invalidateStream(interactionId);
                        this.setStreamingState(interactionId, false, false);
                        this.broadcastEvent('tool_call_result', {
                            toolCallId: data.toolCallId,
                            name: data.name || 'run_shell',
                            result: 'Declined by user',
                            isError: false,
                            conversationId: interactionId,
                        }, interactionId);
                        this.broadcastEvent('stream_done', { stopReason: 'USER_ABORTED', conversationId: interactionId }, interactionId);
                    }
                    await this.handleGetState(ws);
                }
                break;
            case 'get_conversations':
                if (!this.shouldRunCommand('get_conversations', 1500)) return;
                await this.handleGetConversations(ws);
                break;
            case 'load_conversation':
                await this.handleLoadConversation(data.id || data.conversationId, ws);
                break;
            case 'get_models':
                if (!this.shouldRunCommand('get_models', 1500)) return;
                await this.handleGetModels(ws);
                break;
            case 'select_model':
                if (data.modelId) {
                    const model = this.state.models.find(m => m.id === data.modelId || m.label === data.modelId);
                    if (model) {
                        this.state.selectedModelId = model.id;
                        this.broadcastEvent('model_selected', { modelId: model.id });
                    } else {
                        this.state.selectedModelId = data.modelId;
                        this.broadcastEvent('model_selected', { modelId: data.modelId });
                    }
                }
                break;
            case 'get_state':
                if (!this.shouldRunCommand('get_state', 750)) return;
                await this.handleGetState(ws);
                break;
            case 'confirm_action':
                try {
                    if (data.confirmed) {
                        await vscode.commands.executeCommand('antigravity.agent.acceptAgentStep');
                    } else {
                        await vscode.commands.executeCommand('antigravity.agent.rejectAgentStep');
                    }
                } catch { }
                break;
            case 'get_workspaces':
                await this.handleGetWorkspaces(ws);
                break;
            case 'get_project_files':
                await this.handleGetProjectFiles(data.path || '', ws);
                break;
            case 'get_file_diff':
                await this.handleGetFileDiff(ws);
                break;
            case 'get_file_content':
                await this.handleGetFileContent(data.path || '', ws);
                break;
            case 'get_events_since':
                await this.handleGetEventsSince(data.lastSeqId || 0, ws);
                break;
            case 'debug_log':
                if (data.message) {
                    console.log(`[Amaya Remote DEBUG] ${data.message}`);
                    this.broadcastEvent('debug_log', { message: data.message, timestamp: Date.now() });
                }
                break;
        }
    }

    private async handleGetConversations(ws: WebSocket.WebSocket) {
        const now = Date.now();
        const currentWs = this.getCurrentWorkspace();
        const activeId = (this.api as any).httpCore?.cascadeId;

        // Get whatever we have in cache or on disk (FAST)
        const metadatas = await this.api.getConversationsMetadata();

        // Final fallback: Ensure active conversation has a workspace path
        const toReadableTitle = (input: string): string => {
            const cleaned = (input || '')
                .replace(/[#*_`>\-]+/g, ' ')
                .replace(/\s+/g, ' ')
                .trim();
            if (!cleaned) return '';
            return cleaned.length > 50 ? `${cleaned.substring(0, 47)}...` : cleaned;
        };

        const isFallbackTitle = (title: string, id: string): boolean => {
            if (!title) return true;
            if (title === `Chat ${id.substring(0, 6)}`) return true;
            return /^Chat\s+[a-f0-9]{6}$/i.test(title);
        };

        const enriched = metadatas.map(m => {
            let title = m.title;
            let workspacePath = m.workspacePath;

            // Ensure Android can categorize conversations (avoid null workspace => Uncategorized).
            // Priority: original workspace -> active conversation fallback -> current workspace fallback.
            if (!workspacePath && m.id === activeId && currentWs) {
                workspacePath = currentWs.path;
            } else if (!workspacePath && currentWs) {
                workspacePath = currentWs.path;
            }

            // Replace generic fallback titles when preview already has meaningful text.
            if (isFallbackTitle(title, m.id) && m.preview && m.preview !== '...') {
                const fromPreview = toReadableTitle(m.preview.split('\n')[0] || m.preview);
                if (fromPreview) {
                    title = fromPreview;
                }
            }

            return { ...m, title, workspacePath };
        });

        this.sendToClient(ws, {
            event: 'conversations_list',
            data: {
                conversations: enriched,
                currentWorkspacePath: currentWs?.path || null
            }
        });
    }

    private parseMessageAttachments(raw: any): IDEMessageAttachment[] {
        if (!Array.isArray(raw)) return [];
        return raw
            .map((item: any) => ({
                mimeType: typeof item?.mimeType === 'string' ? item.mimeType : '',
                dataBase64: typeof item?.dataBase64 === 'string' ? item.dataBase64 : '',
                fileName: typeof item?.fileName === 'string' ? item.fileName : undefined,
            }))
            .filter((item: IDEMessageAttachment) => item.mimeType.trim().length > 0 && item.dataBase64.trim().length > 0);
    }

    private async handleSendMessage(content: string, ws: WebSocket.WebSocket, conversationId?: string, conversationMode: IDEConversationMode = 'planning', attachments: IDEMessageAttachment[] = []) {
        if (!content.trim() && attachments.length === 0) return;

        this.lastUserSendAt = Date.now();

        let targetId = conversationId || this.state.activeCascadeId;
        if (!targetId) {
            // SAFE FALLBACK: check if there's a recent conversation before creating a new one
            try {
                const metas = await this.api.getConversationsMetadata();
                if (metas && metas.length > 0) {
                    const latest = metas.reduce((a, b) => (a.lastModified >= b.lastModified ? a : b));
                    targetId = latest?.id || null;
                }
            } catch { /* ignore */ }

            if (!targetId) {
                const id = await this.api.startCascade();
                if (!id) {
                    this.broadcastEvent('error', { message: 'Failed to create new conversation' });
                    return;
                }
                targetId = id;
            }
            this.state.activeCascadeId = targetId;
        }
        this.conversationModeMap.set(targetId, conversationMode);
        // CRITICAL: broadcast active conversation before any streaming events.
        // Android filters per-conversation events; if it still has an old activeId,
        // it will drop the first thinking/toolcall/text events for the new conversation.
        this.broadcastEvent('active_conversation', { conversationId: targetId }, targetId);
        this.setStreamingState(targetId, true, true);

        let ignoreBeforeIndex = 0;
        let previousSteps: any[] = [];
        if (!this.attachedStreamIds.has(targetId)) {
            try {
                previousSteps = await Promise.race([
                    this.api.getTrajectory(targetId),
                    new Promise<any[]>((resolve) => setTimeout(() => resolve([]), 1500))
                ]);
                ignoreBeforeIndex = Array.isArray(previousSteps) ? previousSteps.length : 0;
            } catch { ignoreBeforeIndex = 0; previousSteps = []; }
        }

        console.log(`[Amaya MessageHandler] Send to ${targetId}, ignoreBeforeIndex: ${ignoreBeforeIndex}`);

        const sent = await this.api.sendMessage(targetId, content, this.state.selectedModelId, conversationMode, attachments);
        if (!sent) {
            const errDesc = (this.api as any).getLastHttpError?.() || 'Unknown';
            this.setStreamingState(targetId, false, false);
            this.broadcastEvent('error', { message: `Failed to send message: ${errDesc}`, conversationId: targetId }, targetId);
            return;
        }

        this.broadcastEvent('new_assistant_message', { conversationId: targetId }, targetId);

        try {
            if (!this.attachedStreamIds.has(targetId)) {
                const token = (this.streamSessionToken.get(targetId) || 0) + 1;
                this.streamSessionToken.set(targetId, token);
                const callbacks = this.createStreamCallbacks(targetId, token);
                this.attachedStreamIds.add(targetId);
                await this.api.streamForResponse(targetId, callbacks, ignoreBeforeIndex, previousSteps);
            }
        } catch (e: any) {
            console.error('[Amaya MessageHandler] Send stream error:', e.message);
            this.setStreamingState(targetId, false, false);
            this.broadcastEvent('error', { message: e.message, conversationId: targetId }, targetId);
        }
    }

    private async handleNewChat(ws: WebSocket.WebSocket) {
        const id = await this.api.startCascade();
        if (id) {
            this.state.activeCascadeId = id;
            this.conversationModeMap.set(id, 'planning');
            // Ensure clients switch active conversation immediately.
            this.broadcastEvent('active_conversation', { conversationId: id }, id);
            this.broadcastEvent('new_conversation', { conversationId: id }, id);
        } else {
            this.broadcastEvent('error', { message: 'Failed to create new conversation' });
        }
    }

    private async handleGetState(ws: WebSocket.WebSocket) {
        await this.handleGetModels(ws);

        let messages: any[] = [];
        let activeId = this.state.activeCascadeId;

        // Prefer a currently streaming conversation first to prevent active_conversation
        // from flipping to unrelated "latest modified" conversations during recovery.
        const streamingCandidates: string[] = [];
        for (const [id, isStreaming] of this.streamingMap.entries()) {
            if (isStreaming) streamingCandidates.push(id);
        }
        if (streamingCandidates.length > 0) {
            activeId = streamingCandidates[0];
            this.state.activeCascadeId = activeId;
            console.log(`[Amaya MessageHandler] Using streaming conversation as active: ${activeId}`);
        }

        // If the server restarted, we lose in-memory activeCascadeId.
        // For recovery, prefer the IDE client's last active cascade id if available.
        if (!activeId) {
            const lastActive = (this.api as any)?.lastActiveCascadeId;
            if (lastActive) {
                activeId = lastActive;
                this.state.activeCascadeId = lastActive;
                console.log(`[Amaya MessageHandler] Restored active conversation from lastActiveCascadeId: ${activeId}`);
            }
        }

        if (!activeId) {
            try {
                const metas = await this.api.getConversationsMetadata();
                if (metas && metas.length > 0) {
                    const latest = metas.reduce((a, b) => (a.lastModified >= b.lastModified ? a : b));
                    if (latest?.id) {
                        activeId = latest.id;
                        this.state.activeCascadeId = latest.id;
                        console.log(`[Amaya MessageHandler] Inferred active conversation: ${activeId}`);
                    }
                }
            } catch (e: any) {
                console.error('[Amaya MessageHandler] Failed to infer active conversation:', e.message);
            }
        }

        // Always broadcast active conversation to Android first
        if (activeId) {
            console.log(`[Amaya MessageHandler] Broadcasting active_conversation: ${activeId}`);
            this.broadcastEvent('active_conversation', { conversationId: activeId }, activeId);
        }

        if (activeId) {
            try {
                // If we are currently streaming, get the "hot" messages from the active loop
                // rather than waiting for a slow REST trajectory fetch.
                const hotMessages = this.api.getCurrentMessages(activeId);
                if (hotMessages && hotMessages.length > 0) {
                    messages = this.mapMessagesForUi(hotMessages);
                } else {
                    const rawMessages = await this.api.getMessages(activeId);
                    messages = this.mapMessagesForUi(rawMessages);
                }
            } catch (e: any) {
                console.error('[Amaya MessageHandler] Failed to fetch state messages:', e.message);
            }

            // Critical: if the prompt/stream was initiated from IDE (Antigravity), Android may reconnect mid-stream.
            // Attach a stream listener so text_delta/stream_done can be forwarded.
            this.ensureStreamAttached(activeId);
        }

        const selectedModel = this.state.models.find(m => m.id === this.state.selectedModelId);
        const currentWs = this.getCurrentWorkspace();

        const isLoading = activeId ? (this.loadingMap.get(activeId) || false) : false;
        const isStreaming = activeId ? (this.streamingMap.get(activeId) || false) : false;

        // Keep global state consistent for legacy consumers.
        this.state.isLoading = isLoading;
        this.state.isStreaming = isStreaming;

        this.sendToClient(ws, {
            event: 'state_sync', data: {
                messages,
                isLoading,
                isStreaming,
                currentModel: selectedModel?.id || this.state.selectedModelId || '',
                conversationMode: this.getConversationMode(activeId),
                toolExecutions: [],
                appName: 'Antigravity / Framework',
                appVersion: '2.0.0',
                currentWorkspace: currentWs ? { name: currentWs.name, path: currentWs.path } : null,
                conversationId: activeId,
            }
        });
    }

    private modelsCache: { models: any[], timestamp: number } | null = null;

    private async handleGetModels(ws: WebSocket.WebSocket) {
        const now = Date.now();
        let models = this.state.models;
        
        if (!this.modelsCache || now - this.modelsCache.timestamp > 60000 || !models.length) {
            models = await this.api.getModels();
            this.state.models = models;
            this.modelsCache = { models, timestamp: now };
