const WebSocket = require('ws');
const fs = require('fs');
const path = require('path');

const PORT = 8765;
const wss = new WebSocket.Server({ port: PORT, host: '0.0.0.0' });

console.log(`[Test Server] Memulai server di port ${PORT}...`);

wss.on('connection', (ws) => {
    console.log('[Test Server] Client connected. Generating RAW AI Iteration payload...');

    const workspaceRoot = path.resolve(__dirname, '..', '..');
    const outputPath = path.resolve(__dirname, 'raw-iteration.json');

    // 1. Check Workspace (Recursive)
    let allFiles = [];
    try {
        allFiles = fs.readdirSync(workspaceRoot, { recursive: true });
    } catch (err) {
        console.error(`[Test Server] Gagal readdir: ${err.message}`);
        allFiles = [err.message];
    }

    // 2. Define High-Level Prompt
    const aiPrompt = "Analyze the entire codebase structure, check for potential security risks in the 'app' module, and suggest performance optimizations for the 'amaya-remote-extension'.";

    // 3. Construct RAW AI Iteration Object
    const payload = {
        iteration_type: "FULL_WORKSPACE_SCAN",
        prompt: aiPrompt,
        workspace: {
            root: workspaceRoot,
            count: allFiles.length,
            files: allFiles
        },
        timestamp: new Date().toISOString()
    };

    const rawJson = JSON.stringify(payload, null, 2);

    // 4. SAVE TO JSON FILE (As requested)
    try {
        fs.writeFileSync(outputPath, rawJson);
        console.log(`[Test Server] ✅ File RAW tersimpan ke: ${outputPath}`);
    } catch (err) {
        console.error(`[Test Server] Gagal simpan file: ${err.message}`);
    }

    // 5. Send RAW Output over Socket
    ws.send(rawJson);
