    console.log('Connected to test server');
});

ws.on('message', (data) => {
    console.log('Received JSON output:');
    console.log(JSON.stringify(JSON.parse(data), null, 2));
    ws.close();
    process.exit(0);
});

ws.on('error', (err) => {
    console.error('Connection error:', err.message);
    process.exit(1);
});

