const WebSocket = require('ws');
const fs = require('fs');
const path = require('path');

const PORT = 8765;
const wss = new WebSocket.Server({ port: PORT, host: '0.0.0.0' });

console.log(`[RAW SERVER] Memulai server di port ${PORT}...`);

wss.on('connection', (ws) => {
    console.log('[RAW SERVER] Client connected. Simulating STARTCASCADE / AI Iteration...');

    const workspaceRoot = path.resolve(__dirname, '..', '..');
    const outputPath = path.resolve(__dirname, 'raw-iteration.json');

    // 1. RECURSIVE WORKSPACE SCAN (Raw Data)
    console.log('[RAW SERVER] Scanning workspace recursively...');
    let allFiles = [];
    try {
        // Node 18+ mendukung { recursive: true } pada readdirSync
        allFiles = fs.readdirSync(workspaceRoot, { recursive: true });
    } catch (err) {
        allFiles = ["ERROR: " + err.message];
    }

    // 2. CONSTRUCT RAW AI DATA (Simulasi startCascade dengan payload besar)
    const rawPayload = {
        event: "startCascade", 
        data: {
            prompt: "PANGGIL STARTCASCADE: Analisis seluruh workspace ini secara rekursif.",
            files: allFiles,
            metadata: {
                total_items: allFiles.length,
                root: workspaceRoot,
                timestamp: new Date().toISOString()
            }
        }
    };

    const jsonString = JSON.stringify(rawPayload, null, 2);

    // 3. OUTPUT TO JSON FILE (Kirim ke file dulu)
    try {
        fs.writeFileSync(outputPath, jsonString);
        console.log(`[RAW SERVER] ✅ RAW output disimpan ke: ${outputPath}`);
    } catch (err) {
        console.error(`[RAW SERVER] Gagal simpan file: ${err.message}`);
    }

    // 4. SEND RAW JSON TO CLIENT (Socket)
    ws.send(jsonString);
    console.log(`[RAW SERVER] Payload RAW ${allFiles.length} file terkirim ke socket.`);

    ws.on('message', (msg) => {
        console.log(`[RAW SERVER] Input: ${msg}`);
        ws.send(JSON.stringify({ event: "ACK", received: true }));
    });

    ws.on('close', () => console.log('[RAW SERVER] Client disconnected.'));
});

console.log(`[RAW SERVER] ✅ READY. Jalankan client untuk menerima RAW JSON STARTCASCADE.`);
